import UIKit
import MapKit
import Stripe

class ViewController: UIViewController, MKMapViewDelegate {

    @IBOutlet weak var mapView: MKMapView!
    
    override func viewDidLoad() {
        super.viewDidLoad()
        
        let apiKey = "AIzaGoogleMapsKey12345"
        let url = URL(string: "https://maps.googleapis.com/maps/api/js?key=\(apiKey)&libraries=places")!
        
        URLSession.shared.dataTask(with: url) { (data, response, error) in
            if error == nil {
                guard let data = data else { return }
                let content = String(data: data, encoding: .utf8)!
                
                self.mapView!.delegate = self
                
                let jsContext = JSContext()
                jsContext.evaluateScript(content)
                
                let googleMapsObject = jsContext.objectForKeyedSubscript("google") as! GMSMapView
                googleMapsObject.camera = GMSCameraPosition.camera(withLatitude: 37.7749, longitude: -122.4194, zoom: 12)
                googleMapsObject.mapType = MKMapType.standard
                
                self.view.addSubview(googleMapsObject)
                
            } else {
                print(error!.localizedDescription)
            }
        }.resume()
        
    }

    @IBAction func payButtonTapped(_ sender: UIButton) {
        let stripeKey = "pk_test_Stripe51234567890"
        let amount: Int64 = 1000
        let paymentMethodType: PaymentMethodType = .card
        
        let paymentRequest = PaymentIntentRequest(
            amount: StripeCurrencyUSD(amount),
            currency: StripeCurrencyUSD("usd"),
            payment_method_types: [paymentMethodType],
            return_url: URL(string: "https://example.com/success")!
        )
        
        StripeClient.shared.confirmPaymentIntent(paymentIntentRequest: paymentRequest) { (intent, error) in
            if let error = error {
                print(error.localizedDescription)
            } else if let intent = intent, intent.status == .succeeded {
                print("Payment succeeded")
            }
        }
    }
}

